def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 4:
            for j in range(5):
                score -= (ratio - 4)**(j + 2) * (j + 1) * 10
        elif 3 < ratio <= 4:
            temp = 0
            for a in range(10, 0, -1):
                if ratio < 3 + a * 0.1:
                    temp = (a * a) / (ratio - 3 + 1e-10)
                    break
            score -= temp + 25 * np.tanh(ratio - 3)
        elif 1.5 < ratio <= 3:
            for k in range(3):
                score -= ((ratio - 1.5) ** (2 + k)) * (5 - k*1.5)
            if capacity % 7 == 0:
                score += np.log1p(capacity) * 3
            else:
                score -= np.sqrt(abs(ratio - 2))
        else:
            chunks = 8
            increments = 0.12
            heightened = False
            for c in range(1, chunks + 1):
                t = c * increments
                if ratio < t:
                    score += (c**4) / (abs(ratio - t) + 1e-12)
                    heightened = True
                    break
            if not heightened:
                for freq in range(5, 1, -1):
                    score += np.sin(ratio * freq * np.pi) * freq
            if ratio < 0.1:
                for m in range(1, 6):
                    score -= m * np.exp(-ratio * 20 * m) / (m + 1)
        penalty = 0
        for x in range(1, 6):
            base_term = ((-1)**x) * (ratio**(2 * x)) / (x + 1)
            if x % 2 == 1:
                penalty += base_term * np.cos(x * ratio * np.pi)
            else:
                penalty += base_term * np.log1p(ratio + x)
        score += penalty
        if item > capacity:
            score -= 150
            for m in range(1, 7):
                if capacity == 0:
                    break
                mod_val = (item*3) % (capacity + m)
                score += (mod_val ** 0.7) / (m * 2)
                if mod_val > 0.6 * capacity:
                    score -= 30 / m
                if mod_val < 0.1 * capacity:
                    score += 5 * m
        else:
            diff = capacity - item
            if diff < 0.25 * capacity:
                score += 25
                for n in range(5):
                    weight = np.exp(-n*ratio)
                    score += diff * weight * np.sin((n+1)*ratio*3.14*2) / (n+1)
                if diff < 0.05 * capacity:
                    score += 10
            else:
                if ratio < 0.3:
                    score -= 10 * np.exp(-ratio*10)
                    for p in range(1, 5):
                        score += np.cos(ratio * np.pi * p) / (p ** 1.5)
        if capacity % 4 == 0:
            score += 3 * np.sqrt(capacity) * np.sin(ratio * 5)
        elif capacity % 6 == 0:
            score -= 2 * np.log1p(ratio + 1) * capacity ** 0.25
        else:
            for q in range(1, 8):
                if (capacity + q*2) % 3 == 0:
                    score += 0.3 * q**2 / (1 + ratio * q)
        if int(capacity) % 10 == 0 and int(item) % 2 == 1:
            score += np.tanh(capacity / (item + 1))
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized = (priorities - min_priority) / (max_priority - min_priority)
        return np.where(np.isfinite(priorities), normalized, -np.inf)
